{"file_path":"/home/user/workspace/app/admin/catalog/page.tsx","content":"import { cacheTag, cacheLife, revalidateTag } from "next/cache";
import { getAllProducts, syncCatalog } from "@/lib/db";

async function getCachedProducts() {
  "use cache";
  cacheTag("products");
  cacheLife("hours");

  return getAllProducts();
}

export default async function AdminCatalogPage() {
  const products = await getCachedProducts();

  async function syncAction(formData: FormData) {
    "use server";

    // Kick off the upstream sync without waiting for it to finish.
    // Sync jobs can touch thousands of SKUs, so we serve stale content
    // while the cache refreshes in the background.
    syncCatalog().catch(() => {});

    // Stale-while-revalidate: serve stale immediately while fetching fresh
    // data in the background.  All views tagged with "products" will
    // eventually see the updated catalog.
    revalidateTag("products", "max");
  }

  return (
    <main style={{ maxWidth: 960, margin: "0 auto", padding: "2rem 1rem" }}>
      <h1 style={{ marginBottom: "0.25rem" }}>Product Catalog</h1>
      <p style={{ marginTop: 0, color: "#666" }}>
        {products.length} SKUs &middot; cached with stale-while-revalidate
      </p>

      <form action={syncAction}>
        <button
          type="submit"
          style={{
            padding: "0.5rem 1.25rem",
            fontSize: "0.95rem",
            fontWeight: 600,
            cursor: "pointer",
            background: "#0a7cff",
            color: "#fff",
            border: "none",
            borderRadius: 6,
          }}
        >
          Sync Latest Catalog
        </button>
        <p style={{ fontSize: "0.85rem", color: "#888", marginTop: "0.35rem" }}>
          Submitting starts an upstream sync and revalidates the cache in the
          background. The page may briefly show stale data.
        </p>
      </form>

      <div style={{ overflowX: "auto", marginTop: "1.5rem" }}>
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            fontSize: "0.9rem",
          }}
        >
          <thead>
            <tr style={{ textAlign: "left", borderBottom: "2px solid #ddd" }}>
              <th style={thStyle}>SKU</th>
              <th style={thStyle}>Name</th>
              <th style={thStyle}>Category</th>
              <th style={{ ...thStyle, textAlign: "right" }}>Price</th>
              <th style={{ ...thStyle, textAlign: "right" }}>Inventory</th>
              <th style={thStyle}>Last Updated</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: "1px solid #eee" }}
              >
                <td style={tdStyle}>
                  <code style={{ fontSize: "0.8rem" }}>{product.sku}</code>
                </td>
                <td style={tdStyle}>{product.name}</td>
                <td style={tdStyle}>{product.category}</td>
                <td style={{ ...tdStyle, textAlign: "right" }}>
                  ${product.price}
                </td>
                <td
                  style={{
                    ...tdStyle,
                    textAlign: "right",
                    color: product.inventory < 20 ? "#d32f2f" : "inherit",
                    fontWeight: product.inventory < 20 ? 600 : "normal",
                  }}
                >
                  {product.inventory}
                </td>
                <td style={tdStyle}>
                  {new Date(product.updatedAt).toLocaleDateString("en-US", {
                    month: "short",
                    day: "numeric",
                    hour: "2-digit",
                    minute: "2-digit",
                  })}
